def longest_substring_with_at_most_k_distinct_characters(s: str, k: int) -> int:
    if k == 0:
        return 0

    window_start = 0
    max_length = 0
    char_counts = {}

    for window_end in range(len(s)):
        right_char = s[window_end]
        char_counts[right_char] = char_counts.get(right_char, 0) + 1

        while len(char_counts) > k:
            left_char = s[window_start]
            char_counts[left_char] -= 1
            if char_counts[left_char] == 0:
                del char_counts[left_char]
            window_start += 1

        max_length = max(max_length, window_end - window_start + 1)

    return max_length
